// Get the first incoming item from AI Agent
const item = $json.output;

// Clone to avoid mutating original
let raw = item;

// If the AI Agent output is a string (code fenced), clean and parse it
if (typeof raw === 'string') {
  const cleaned = raw
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();
  //console.log("cleaned value:" + cleaned);
  try {
    raw = JSON.parse(cleaned);
  } catch (err) {
    throw new Error("AI Agent output is not valid JSON after removing code fences.");
  }
}
console.log(raw);
// Validate structure
if (!raw || typeof raw !== 'object') {
  throw new Error("AI Agent output is not an object.");
}

if (!raw.pipeline || !Array.isArray(raw.pipeline)) {
  throw new Error("Missing or invalid 'pipeline' field (must be array).");
}
//console.log(raw.collection);
//console.log(raw.pipeline);
const returnValue = {
    json: {
      collection: raw.Collection,
      pipeline: raw.pipeline
    }
  };
// ✅ IMPORTANT: json MUST be an object
return returnValue;

// Combine all MongoDB items into a single array under "data"
const items = $input.all();

// Extract only the JSON payloads (your schema fields)
const combined = items.map(i => i.json);

// Return ONE item with the entire dataset
return [
  {
    json: {
      data: combined
    }
  }
];

const rows = $input.first().json.data.map(item => item);
// Count only data rows (header is not included here)

const siteCount = rows.length - 1;
const headers = Object.keys(rows[0]);

let table = headers.join('\t') + '\n';
//const count = rows.length;

for (const row of rows) {
  table += headers.map(h => row[h]).join('\t') + '\n';
}

return [
  {
    json: {
      emailBody: `Here is your MongoDB data:\n\n${table}`,
      siteCount
    }
  }
];
